import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface City {
  name: string;
  localTime: string;
  dateDifference: string;
}

interface WorldClockData {
  cities: City[];
}

export default function Widget() {
  const worldClockData = response.data as WorldClockData;
  const theme = response.meta.theme;
  const isDarkTheme = theme === 'dark';

  return (
    <Card sx={{ width: 'fit-content', minWidth: 300, maxWidth: 400, bgcolor: isDarkTheme ? '#333' : '#fff' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: isDarkTheme ? '#fff' : '#000', fontWeight: 700 }}>
            World Clock
          </Typography>
          {worldClockData.cities.map((city, index) => (
            <Box key={index} sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <Typography variant="body1" sx={{ color: isDarkTheme ? '#fff' : '#000' }}>
                {city.name}
              </Typography>
              <Box textAlign="right">
                <Typography variant="body1" sx={{ color: isDarkTheme ? '#fff' : '#000' }}>
                  {city.localTime}
                </Typography>
                <Typography variant="caption" sx={{ color: isDarkTheme ? '#aaa' : '#666' }}>
                  {city.dateDifference}
                </Typography>
              </Box>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
